// Stripe Webhook-Signatur verifizieren (HMAC-SHA256)
const crypto = require('crypto');

const rawBody = $input.item.binary?.data
  ? Buffer.from($input.item.binary.data, 'base64').toString('utf8')
  : JSON.stringify($input.item.json.body || $input.item.json);

const stripeSignature = $input.item.json.headers?.['stripe-signature'] || '';
const webhookSecret = $env.STRIPE_WEBHOOK_SECRET;

if (!webhookSecret) {
  throw new Error('STRIPE_WEBHOOK_SECRET nicht konfiguriert');
}

// Timestamp + Payload extrahieren
const parts = stripeSignature.split(',');
const tPart = parts.find(p => p.startsWith('t='));
const v1Part = parts.find(p => p.startsWith('v1='));

if (!tPart || !v1Part) {
  throw new Error('Ungültige Stripe-Signatur-Header');
}

const timestamp = tPart.split('=')[1];
const signature = v1Part.split('=')[1];

// Replay-Angriff verhindern: max. 5 Minuten alt
const now = Math.floor(Date.now() / 1000);
if (Math.abs(now - parseInt(timestamp)) > 300) {
  throw new Error('Stripe Webhook zu alt (Replay-Schutz)');
}

// Signatur berechnen
const signedPayload = `${timestamp}.${rawBody}`;
const expectedSig = crypto
  .createHmac('sha256', webhookSecret)
  .update(signedPayload)
  .digest('hex');

if (expectedSig !== signature) {
  throw new Error('Stripe-Signatur ungültig – Anfrage abgewiesen');
}

// Event-Daten zurückgeben
const event = JSON.parse(rawBody);
return [{ json: { event, verified: true, timestamp: new Date().toISOString() } }];

const event = $json.event;
const charge = event.data?.object || {};
const metadata = charge.metadata || {};

// Betrag: Stripe in Cent → Euro
const amountTotal = (charge.amount || 0) / 100;
const amountCurrency = (charge.currency || 'eur').toUpperCase();

// Payment-Methode bestimmen
let paymentInstrumentId = 1; // Default: Stripe Card
if (charge.payment_method_details?.type === 'sepa_debit') {
  paymentInstrumentId = 2;
} else if (charge.payment_method_details?.type === 'eps') {
  paymentInstrumentId = 6;
}

// Contribution-Typ bestimmen
const contributionTypeMap = {
  membership: 1,
  donation: 2,
  event: 3,
  default: 2
};
const financialTypeId = contributionTypeMap[metadata.purpose] || contributionTypeMap.default;

// CiviCRM API4-Payload bauen
const civicrmPayload = {
  contact_id: metadata.contact_id || metadata.civicrm_contact_id || null,
  financial_type_id: financialTypeId,
  payment_instrument_id: paymentInstrumentId,
  receive_date: new Date(charge.created * 1000).toISOString().split('T')[0],
  total_amount: amountTotal,
  currency: amountCurrency,
  source: `Stripe ${event.type} – ${charge.id}`,
  trxn_id: charge.id,
  payment_processor_id: 1,  // Stripe-Processor-ID in CiviCRM
  contribution_status_id: 1, // 1 = Completed
  note: `Stripe Event: ${event.id}\nKunde: ${charge.billing_details?.email || 'Unbekannt'}`,
  // Opt-in falls vorhanden
  campaign_id: metadata.campaign_id || null,
  is_test: charge.livemode === false ? 1 : 0
};

return [{
  json: {
    civicrmPayload,
    originalCharge: charge,
    stripeEventId: event.id,
    eventType: event.type,
    payer_email: charge.billing_details?.email || metadata.email || '',
    payer_name: charge.billing_details?.name || '',
    amount: amountTotal,
    currency: amountCurrency
  }
}];

const event = $('verify-signature').item.json.event;
const charge = event.data?.object || {};

// CiviCRM-Contribution mit Status 'Failed' anlegen
const civicrmFailedPayload = {
  financial_type_id: 2,
  receive_date: new Date().toISOString().split('T')[0],
  total_amount: (charge.amount || 0) / 100,
  currency: (charge.currency || 'eur').toUpperCase(),
  source: `Stripe charge.failed – ${charge.id}`,
  trxn_id: charge.id,
  contribution_status_id: 4, // 4 = Failed
  note: `Fehlgeschlagen: ${charge.failure_message || 'Unbekannt'}`
};

return [{ json: { civicrmFailedPayload, charge, alertEmail: 'admin@menschlichkeit-oesterreich.at' } }];

