const error = $input.item.json.error || 'Unbekannter Fehler';
const nodeError = $input.item.json.node?.name || 'Unbekannter Node';

console.error(`[Stripe Webhook] Fehler in ${nodeError}: ${error}`);

// In Produktionssystem: DLQ-Webhook aufrufen
return [{
  json: {
    logged: true,
    errorMessage: error,
    failedNode: nodeError,
    timestamp: new Date().toISOString()
  }
}];
